1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — base premiums and processing fee
6	  it("empty item list yields premium of 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it("quote for newcomer's single plain sword (steel, enchantment 3) yields 115 G", () => {
14	    // 100 base + 10 first insurance (per item) = 110, + 5 fee = 115 G
15	    const result = runScenario({
16	      customer: { yearsWithMHPCO: 0 },
17	      steps: [
18	        {
19	          op: "quote",
20	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
21	        },
22	      ],
23	    });
24	    expect(result.results[0]).toEqual({ premium: 115 });
25	  });
26	  it("quote for newcomer's single plain amulet yields 71 G", () => {
27	    // 60 + 6 first ins = 66, + 5 fee = 71
28	    const result = runScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [
31	        {
32	          op: "quote",
33	          items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }],
34	        },
35	      ],
36	    });
37	    expect(result.results[0]).toEqual({ premium: 71 });
38	  });
39	  it("quote for newcomer's single plain staff yields 93 G", () => {
40	    const result = runScenario({
41	      customer: { yearsWithMHPCO: 0 },
42	      steps: [
43	        {
44	          op: "quote",
45	          items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }],
46	        },
47	      ],
48	    });
49	    expect(result.results[0]).toEqual({ premium: 93 });
50	  });
51	  it("quote for newcomer's single plain potion yields 49 G", () => {
52	    const result = runScenario({
53	      customer: { yearsWithMHPCO: 0 },
54	      steps: [
55	        {
56	          op: "quote",
57	          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
58	        },
59	      ],
60	    });
61	    expect(result.results[0]).toEqual({ premium: 49 });
62	  });
63	
64	  // Components and blocks
65	  it("quote for 2 runes yields 60 G (50 base + 5 first ins, rounded up + 5 fee)", () => {
66	    // 2 runes: 2*25 = 50 base + 5 first ins (10%) + 5 fee = 60
67	    const result = runScenario({
68	      customer: { yearsWithMHPCO: 0 },
69	      steps: [
70	        {
71	          op: "quote",
72	          items: [
73	            { type: "rune" },
74	            { type: "rune" },
75	          ],
76	        },
77	      ],
78	    });
79	    expect(result.results[0]).toEqual({ premium: 60 });
80	  });
81	  it.todo("quote for 3 runes applies block, yielding 65 G");
82	  it.todo("quote for 4 runes yields 105 G (no block, block requires exactly 3)");
83	  it.todo("quote for 7 runes yields 180 G (no block)");
84	  it.todo("quote for 2 runes + 1 moonstone yields 80 G (no block, different types)");
85	  it.todo("quote for 3 runes + 3 moonstones applies two blocks, yielding 125 G");
86	
87	  // Item-specific modifiers
88	  it.todo("cursed sword adds 50% surcharge on the item's base premium");
89	  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
90	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
91	  it.todo("cursed sword with enchantment 5 stacks both surcharges");
92	
93	  // Policy-wide modifiers
94	  it.todo("customer with exactly 2 years applies 20% loyalty discount");
95	  it.todo("first insurance adds 10% initial assessment surcharge");
96	  it.todo("follow-up contract applies 15% discount on contracts after the first");
97	
98	  // Multi-item modifier scope
99	  it.todo("cursed surcharge applies only to the cursed item, not to whole policy");
100	
101	  // Rounding
102	  it.todo("premium is rounded up to whole G (MHPCO's favor)");
103	
104	  // Integration examples
105	  it.todo("newcomer with cursed sword yields 165 G");
106	  it.todo("long-standing customer's second contract with cursed enchanted sword yields 160 G");
107	
108	  // Claim — basic processing
109	  it.todo("claim on a regular sword with 500 G damage yields payout 400 G after deductible");
110	  it.todo("claim on a rune with 200 G damage yields payout 100 G after deductible");
111	  it.todo("claim on enchantment-9 sword (steel) with 1000 G damage yields payout 400 G");
112	  it.todo("claim on a dragon-material sword with 800 G damage yields full payout 700 G");
113	  it.todo("dragon-material sword with enchantment 9 and 1000 G damage yields payout 400 G");
114	
115	  // Deductible per damage event
116	  it.todo("multiple damaged items each incur their own deductible");
117	
118	  // Cap
119	  it.todo("payout is capped at twice the insurance sum across successive claims");
120	  it.todo("claim references unknown item rejects the claim");
121	
122	  // CLI errors
123	  it.todo("quote with unknown item type rejects the quote");
124	  it.todo("claim with negative damage amount is rejected");
125	});
