1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	
15	const itemPremium = (item: Item): number => {
16	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
17	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
18	  return basePremium + firstInsuranceSurcharge;
19	};
20	
21	const quotePremium = (items: Item[]): number => {
22	  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
23	  return itemsTotal + PROCESSING_FEE;
24	};
25	
26	type QuoteResult = { premium: number };
27	
28	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
29	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
30	  return { results };
31	};
